// components/feed-client.tsx — cancel on App Router navigation
'use client';
import { useEffect, useState } from 'react';

export function FeedClient() {
  const [items, setItems] = useState<{ id: string; title: string }[]>([]);
  useEffect(() => {
    const ac = new AbortController();
    fetch('/api/feed', { signal: ac.signal })
      .then(r => r.json())
      .then(setItems)
      .catch(err => { if (err.name !== 'AbortError') throw err; });
    return () => ac.abort();
  }, []);
  return <ul>{items.map(i => <li key={i.id}>{i.title}</li>)}</ul>;
}

// app/api/stream/route.ts
export const runtime = 'edge';
export const dynamic = 'force-dynamic';

export function GET() {
  const stream = new ReadableStream({
    async start(controller) {
      for (let i = 0; i < 5; i++) {
        controller.enqueue(`data: ${JSON.stringify({ tick: i })}\n\n`);
        await new Promise(r => setTimeout(r, 1000));
      }
      controller.close();
    },
  });
  return new Response(stream, {
    headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache' },
  });
}

// hooks/useStream.ts
export function useStream(url: string) {
  const [events, setEvents] = useState<unknown[]>([]);
  useEffect(() => {
    const src = new EventSource(url);
    src.onmessage = (e) => setEvents(prev => [...prev, JSON.parse(e.data)]);
    return () => src.close();
  }, [url]);
  return events;
}

